 1	import * as React from 'react';
 2	import { Alert, Flex, FlexItem } from '@patternfly/react-core';
 3	import { useTranslation } from 'react-i18next';
 4	import { ConsoleEmptyState } from './ConsoleEmptyState';
 5	import * as restrictedSignImg from '../../../../imgs/restricted-sign.svg';
 6	
 7	const RestrictedSignIcon = () => {
 8	  const { t } = useTranslation('console-shared');
 9	  return <img src={restrictedSignImg} alt={t('Restricted access')} />;
10	};
11	
12	export const AccessDenied: React.FC = ({ children }) => {
13	  const { t } = useTranslation('console-shared');
14	  return (
15	    <ConsoleEmptyState
16	      data-test="access-denied"
17	      Icon={RestrictedSignIcon}
18	      title={t('Restricted access')}
19	    >
20	      <Flex direction={{ default: 'column' }}>
21	        <FlexItem>{t("You don't have access to this section due to cluster policy")}</FlexItem>
22	        {children && (
23	          <FlexItem>
24	            <Alert variant="danger" className="pf-v5-u-text-align-left" title={t('Error details')}>
25	              {children}
26	            </Alert>
27	          </FlexItem>
28	        )}
29	      </Flex>
30	    </ConsoleEmptyState>
31	  );
32	};
33	AccessDenied.displayName = 'AccessDenied';

